{"code": "import json

# Load data from storage
reviews_file = locals()['var_functions.query_db:6']
books_file = locals()['var_functions.query_db:20']

with open(reviews_file, 'r') as f:
    reviews_2020 = json.load(f)

children_books = locals()['var_functions.query_db:20']  # List from previous query

# Create a dictionary to store book ratings by mapping purchase_id to numeric ID
book_ratings = {}

for review in reviews_2020:
    purchase_id = review['purchase_id']
    rating = float(review['rating'])

    # Extract numeric part from purchase_id (e.g., 'purchaseid_178' -> '178')
    if '_' in purchase_id:
        numeric_id = purchase_id.split('_')[1]
        if numeric_id not in book_ratings:
            book_ratings[numeric_id] = []
        book_ratings[numeric_id].append(rating)

# Calculate average ratings
book_avg_ratings = {}
for numeric_id, ratings in book_ratings.items():
    if len(ratings) > 0:  # Only include books with at least one review
        avg_rating = sum(ratings) / len(ratings)
        book_avg_ratings[numeric_id] = {
            'average_rating': avg_rating,
            'review_count': len(ratings)
        }

# Filter for books with average rating >= 4.5
high_rated_books = {k: v for k, v in book_avg_ratings.items() 
                    if v['average_rating'] >= 4.5}

print('__RESULT__:')
print(json.dumps({
    'total_books_with_reviews': len(book_avg_ratings),
    'high_rated_books_count': len(high_rated_books),
    'sample_high_rated': dict(list(high_rated_books.items())[:5])
}))"}

